Here is a basic implementation of the Union-Find algorithm in Python using the weighted-quick-union approach:

```
class UnionFind:
    def __init__(self, n):
        self.parent = [i for i in range(n)]
        self.size = [1] * n

    def find(self, i):
        root = i
        while root != self.parent[root]:
            root = self.parent[root]

        # Path compression
        while i != root:
            i, self.parent[i] = self.parent[i], root
        return root

    def connected(self, i, j):
        return self.find(i) == self.find(j)

    def union(self, i, j):
        root_i = self.find(i)
        root_j = self.find(j)

        if root_i == root_j:
            return

        # Weighted Quick Union
        if self.size[root_i] < self.size[root_j]:
            self.parent[root_i] = root_j
            self.size[root_j] += self.size[root_i]
        else:
            self.parent[root_j] = root_i
            self.size[root_i] += self.size[root_j]
```

The `__init__` method initializes the `parent` and `size` list to hold the parent node and size of each node respectively. The `find` method takes an index and finds the root of the corresponding element while performing path compression. The `connected` method checks whether the two nodes are connected or not by checking their root. And, the `union` method connects the two nodes by making the root of one node the parent of the root of another node using the weighted-quick-union approach.

Here's an example implementation of the bogosort algorithm in C++:

```
#include <iostream>
#include <cstdlib>
#include <ctime>
#include <vector>

bool is_sorted(const std::vector<int>& nums) {
    for (int i = 0; i < nums.size() - 1; i++) {
        if (nums[i] > nums[i + 1]) {
            return false;
        }
    }
    return true;
}

void bogosort(std::vector<int>& nums) {
    srand(time(NULL)); // seed the random number generator
    while (!is_sorted(nums)) {
        for (int i = 0; i < nums.size(); i++) {
            int random_index = rand() % nums.size();
            std::swap(nums[i], nums[random_index]);
        }
    }
}

int main() {
    std::vector<int> nums = {3, 1, 4, 1, 5, 9, 2, 6};
    bogosort(nums);
    for (int num : nums) {
        std::cout << num << " ";
    }
    std::cout << std::endl;
    return 0;
}
```

This implementation randomly shuffles the input vector until it is sorted, using the `is_sorted` helper function to check if the vector is sorted. Note that bogosort is not a practical sorting algorithm and its performance is generally terrible.
